// ── Locale persistence ──────────────────────────────────────
const STORAGE_KEY = "mercury_ui_lang";

export function getStoredLang(): LangCode {
  try {
    const v = localStorage.getItem(STORAGE_KEY);
    if (v && v in TRANSLATIONS) return v as LangCode;
  } catch {}
  // Browser language detection
  const nav = navigator.language?.split("-")[0] as LangCode;
  if (nav && nav in TRANSLATIONS) return nav;
  return "en";
}

export function setStoredLang(code: LangCode): void {
  try { localStorage.setItem(STORAGE_KEY, code); } catch {}
}

// ── Hook ────────────────────────────────────────────────────
import { useState, useCallback, createContext, useContext, type ReactNode } from "react";
import { createElement } from "react";

interface I18nCtx {
  lang: LangCode;
  t: (key: TranslationKey) => string;
  setLang: (code: LangCode) => void;
}

const I18nContext = createContext<I18nCtx>({
  lang: "en",
  t: (k) => TRANSLATIONS.en[k],
  setLang: () => {},
});

export function I18nProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<LangCode>(getStoredLang);

  const setLang = useCallback((code: LangCode) => {
    setLangState(code);
    setStoredLang(code);
  }, []);

  const t = useCallback((key: TranslationKey): string => {
    const dict = TRANSLATIONS[lang] as Record<string, string>;
    return dict[key] ?? (TRANSLATIONS.en as Record<string, string>)[key] ?? key;
  }, [lang]);

  return createElement(I18nContext.Provider, { value: { lang, t, setLang } }, children);
}

export function useI18n() { return useContext(I18nContext); }
